import{_ as t,o as a,c as i,ag as l}from"./chunks/framework.BwvNCotA.js";const h=JSON.parse('{"title":"Agents And Client Compatibility","description":"","frontmatter":{},"headers":[],"relativePath":"agents.md","filePath":"agents.md"}'),o={name:"agents.md"};function n(s,e,r,c,p,m){return a(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="agents-and-client-compatibility" tabindex="-1">Agents And Client Compatibility <a class="header-anchor" href="#agents-and-client-compatibility" aria-label="Permalink to &quot;Agents And Client Compatibility&quot;">​</a></h1><p>Relay is designed for local-agent workflows where tools expect hosted API shapes.</p><h2 id="typical-agent-flow" tabindex="-1">Typical Agent Flow <a class="header-anchor" href="#typical-agent-flow" aria-label="Permalink to &quot;Typical Agent Flow&quot;">​</a></h2><ol><li>Agent client sends OpenAI- or Anthropic-style request.</li><li>Relay normalizes request fields to a canonical internal model.</li><li>Relay forwards to upstream OpenAI-like chat endpoint.</li><li>Relay maps upstream responses back to client protocol shape.</li></ol><h2 id="practical-compatibility-scope" tabindex="-1">Practical Compatibility Scope <a class="header-anchor" href="#practical-compatibility-scope" aria-label="Permalink to &quot;Practical Compatibility Scope&quot;">​</a></h2><p>Relay works best with clients that allow custom base URLs and model IDs.</p><ul><li>OpenAI-compatible clients: chat/responses/completions style workflows</li><li>Anthropic-compatible clients: messages workflows</li><li>Local agent tools (for example Cline) using OpenAI-compatible mode</li></ul><h2 id="known-limits" tabindex="-1">Known Limits <a class="header-anchor" href="#known-limits" aria-label="Permalink to &quot;Known Limits&quot;">​</a></h2><p>Relay intentionally does not implement full hosted platform orchestration APIs.</p><p>See <a href="./api-compatibility">API Compatibility</a> for explicit support boundaries.</p>',10)])])}const b=t(o,[["render",n]]);expo